}
  return (
    <header>
      <div>
        <ul className="flex bg-red-600 justify-around">
         <Link to={'/'}>
         <li>HOME</li>
         </Link>
          <li>ABOUT</li>
          <li>CONTACT</li>
          <li><Link to={'/account'}>
          {user?.name}
          </Link>
          </li>
          {user ? (
            <li> 
            <button onClick={logout} >Logout</button>
            </li>  
          ) : (
            <Link to={"/register"}>
              <li>Register</li>
            </Link>
          )}
        </ul>
      </div>
    </header>
  );
};

export default Header;
